var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"상대를 이해하기 위해 노력하는 것. 상대와 계속 함께 있고 싶다고 느끼는 것.","JPN":"相手を理解しようと努力すること。相手と永遠に共にいたいと思うこと。","ENG":"Trying to understand someone... Wanting to stay with them forever...","TWN":"努力去理解對方。感受到想要一直和對方在一起。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"단점. 그리고 장점…. 상대의 모든 것을 받아들이는 것…….","JPN":"短所、そして長所……相手のすべてを受け入れること……","ENG":"Flaws. And strengths... Accepting everything...","TWN":"缺點，還有優點……接受對方的一切……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"인간의 개념을 빌리자면, 그것은 <color=#ffd34c>사랑</color>이라고 해석됩니다.","JPN":"人間の概念を借りるなら、それは<color=#ffd34c>愛</color>と解釈できます。","ENG":"If I borrow the human concept, that is defined as <color=#ffd34c>love</color>.","TWN":"用人類的概念，那可以解釋為<color=#ffd34c>愛</color>。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그렇다면 저는 틀림없이 당신을 사랑하고 있는 것이겠죠.","JPN":"それなら私は間違いなく、あなたを愛しているのでしょう。","ENG":"Therefore, I must love you, Captain.","TWN":"那麼我一定是愛上你了吧。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사랑……!?","JPN":"愛……！？","ENG":"Love...?!","TWN":"愛！？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 제가 내린 결론은 하나입니다.","JPN":"したがって、私はひとつの結論を出しました。","ENG":"Therefore, there is one conclusion I have reached.","TWN":"因此，我得出了一個結論。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신과 영원한 동기화를 희망합니다.","JPN":"あなたとの永遠なる同期化を希望します。","ENG":"I desire eternal synchronization with you.","TWN":"希望與你永遠同步。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 그나저나 이거 곤란하게 됐군.","JPN":"ゴホン、それより困ったな。","ENG":"Ahem, in any case, this is quite the predicament.","TWN":"嗯，總之，這確實是個難題。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아시모프가 내린 시험을 통과하지 못하면, 꼼짝없이 프러포즈를 받게 생겼으니까.","JPN":"アシモフの試験を乗り越えられないと、プロポーズを受け入れざるを得なくなる。","ENG":"If I don't pass Asimov's trial, I'll end up receiving that proposal after all.","TWN":"如果我沒通過阿西莫夫的試煉，最後還是會被逼著接受那個提案。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통 주제에 제법 로맨틱한 표현을 쓰긴 했지만, 사실상 전 인류의 목숨을 건 협박입니다.","JPN":"ボロ缶のくせになかなかロマンチックな表現を使いましたが、実際、あれは全人類の命をかけた脅迫ですからね。","ENG":"Junk Metal may have used romantic words, but it was basically a threat against all of humanity.","TWN":"鐵罐或許說得浪漫，但本質上就是對全人類的威脅。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선은 그 시험인가 뭔가를 해결할 수밖에 없겠군요.","JPN":"まずはその試験だか何だかを解決するしかありません。","ENG":"For now, I suppose we have no choice but to deal with this so-called trial.","TWN":"眼下，我想我們只能硬著頭皮應付這所謂的試煉了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 미나 양에게 연락을…….","JPN":"ではミナさんに連絡を……","ENG":"In that case, I should contact Mina...","TWN":"那麼聯絡米娜……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"발신자 제한이라고……?","JPN":"発信者番号非通知……？","ENG":"An unknown number...?","TWN":"不明來電……？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"안녕, 수연아? 잘 지냈어?","JPN":"やあ、キズナ。元気だった？","ENG":"Hello, Sooyeon. How have you been?","TWN":"你好，秀妍。你最近怎麼樣？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 처음인가? 다친 데는 괜찮고?","JPN":"クリフォトゲーム以来初めてかな？　怪我の具合はどう？","ENG":"Is this the first time since the Qliphoth Game? Are your injuries healing well?","TWN":"這是自逆卡巴拉遊戲後第一次聯絡嗎？傷勢恢復得還好嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나, 나유빈……?","JPN":"い、イチノセ……？","ENG":"N-Na Yubin...?","TWN":"羅，羅瑜斌……？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 왜……?","JPN":"どうしてあなたが……？","ENG":"Why are you...?","TWN":"你怎麼會……？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 오래간만입니다.","JPN":"それから、お久しぶりです。","ENG":"And it's been a while, too.","TWN":"也好久不見了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"때마침 곤란한 일을 겪고 계실 것 같아서, 무례를 무릅쓰고 먼저 연락드렸습니다.","JPN":"ちょうどお困りだろうと思って、無礼を承知で連絡さしあげました。","ENG":"I figured you'd be in some trouble, so I took the liberty of contacting you first.","TWN":"我覺得你可能遇到麻煩了，所以先主動聯絡了你。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……관리자님.","JPN":"……管理者さん。","ENG":"...Administrator.","TWN":"……管理者。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군…….","JPN":"なるほど……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 말대로라면, 그녀가 세피로트 나무의 파편으로 이루고자 하는 소원은…….","JPN":"君の話通りだとすると、彼女がセフィロトの破片で叶えようしている願いは……","ENG":"If what you say is true, then the wish she seeks to fulfill with the Fragment of the Tree of Sephiroth is...","TWN":"照你所說，她想藉由生命樹碎片實現的願望是……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 것을 처음으로 되돌리는 것. 즉, 고향 세계 런던의 부활이겠군.","JPN":"すべてを最初に戻すこと。つまり、故郷の世界のロンドンを復活させることだろうな。","ENG":"To return everything to the beginning. In other words, the restoration of her home world, London.","TWN":"將一切回溯至起點，也就是讓故鄉世界倫敦復活吧？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다, 관리자님.","JPN":"そうです、管理者さん。","ENG":"That is correct, Administrator.","TWN":"正是如此，管理者。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이면세계를 원래대로 되돌리는 것. 그것이야 말로 모든 엑자일러의 염원일 테니까요.","JPN":"裏世界を元の姿に戻すこと。それこそが、すべてのエグザイラーの念願でしょうね。","ENG":"Restoring the Counterside to its original state. That is surely the wish of all Exiles.","TWN":"讓異界回歸原貌，那正是所有流浪者的夙願。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠깐, 이면세계를 되돌린다고……?","JPN":"元の姿に戻す……？　裏世界を？","ENG":"Wait, restoring the Counterside...?","TWN":"等等，讓異界恢復原狀……？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 게 가능하다는 거야?","JPN":"そんなことが、本当に可能なの……？","ENG":"Is something like that even possible?","TWN":"真的有可能嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 불가능하다네.","JPN":"いや、不可能だ。","ENG":"No. It is impossible.","TWN":"不，不可能。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세피로트 나무에 현실을 개변할 힘이 잠들어 있다는 것은 사실이지만…….","JPN":"セフィロトが現実を改変する力を秘めていることは事実だが……","ENG":"It is true that the Tree of Sephiroth holds the power to alter reality, however...","TWN":"改變現實的力量的確沉睡於生命樹中……"},"stage":{"bg":"MS_1101_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"단순히 힘을 가지고 있는 것과 그것을 다룰 수 있는 능력은 전혀 별개의 문제야.","JPN":"単にその力を持っていることと、それを扱える能力があることとは全く別の問題だ。","ENG":"Simply possessing power and being able to wield it are entirely different matters.","TWN":"但擁有力量與能夠駕馭力量，完全是不同的問題。"},"stage":{"bg":"MS_1101_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론, 스완이라면 나름대로 비책을 생각해 두었을지도 모르지.","JPN":"もちろん、スワンなら彼女なりの秘策を用意しているかもしれないが……","ENG":"Of course, Swan may have devised her own contingency.","TWN":"當然，如果是史旺，或許已經準備了某種對策。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 한들, 이미 멸망해 버린 세계를 되돌릴 수 있다고 생각되지는 않아.","JPN":"だからといって、すでに滅んだ世界を蘇らせられるとは到底思えないな。","ENG":"Even so, I don't believe it's possible to restore a world that has already perished.","TWN":"即便如此，我仍不認為她能復原已經毀滅的世界。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};